package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void format_withNormalValues_returnsFormattedString() throws IOException {
        String[] values = new String[] { "a", "b", "c" };
        String result = csvFormat.format((Object[]) values);
        assertNotNull(result);
        assertFalse(result.isEmpty());
        // The default delimiter is comma, default quote is double quote, default record separator CRLF
        // The result should be something like: "a,b,c"
        assertTrue(result.contains("a"));
        assertTrue(result.contains("b"));
        assertTrue(result.contains("c"));
        assertFalse(result.endsWith("\n"));
    }

    @Test
    void format_withNullValues_returnsFormattedStringWithNulls() {
        Object[] values = new Object[] { null, "test", null };
        String result = csvFormat.format(values);
        assertNotNull(result);
        assertTrue(result.contains("test"));
        // null values should be printed as empty strings by default
        assertTrue(result.startsWith(","));
        assertTrue(result.endsWith(",test") || result.endsWith(",test,"));
    }

    @Test
    void format_withEmptyValues_returnsEmptyString() {
        Object[] values = new Object[0];
        String result = csvFormat.format(values);
        assertNotNull(result);
        assertEquals("", result);
    }

    @Test
    void format_whenIOExceptionThrown_throwsIllegalStateException() throws Exception {
        // Create a proxy to mock CSVPrinter that throws IOException on printRecord
        CSVPrinter proxyPrinter = (CSVPrinter) Proxy.newProxyInstance(
                CSVPrinter.class.getClassLoader(),
                new Class<?>[]{CSVPrinter.class, AutoCloseable.class},
                new InvocationHandler() {
                    @Override
                    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                        if ("printRecord".equals(method.getName())) {
                            throw new IOException("IO error");
                        }
                        if ("close".equals(method.getName())) {
                            return null;
                        }
                        // For other methods, return default values or null
                        if (method.getReturnType().isPrimitive()) {
                            if (method.getReturnType() == boolean.class) {
                                return false;
                            }
                            if (method.getReturnType() == int.class) {
                                return 0;
                            }
                            if (method.getReturnType() == long.class) {
                                return 0L;
                            }
                            if (method.getReturnType() == float.class) {
                                return 0f;
                            }
                            if (method.getReturnType() == double.class) {
                                return 0d;
                            }
                            if (method.getReturnType() == byte.class) {
                                return (byte) 0;
                            }
                            if (method.getReturnType() == short.class) {
                                return (short) 0;
                            }
                            if (method.getReturnType() == char.class) {
                                return '\0';
                            }
                        }
                        return null;
                    }
                });

        // Use reflection to create a subclass instance of CSVFormat by calling with* methods to override print()
        CSVFormat format = CSVFormat.DEFAULT;

        CSVFormat formatMock = new CSVFormatProxy(format, proxyPrinter);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            formatMock.format("a", "b");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }

    // Helper subclass to override print(Appendable) method
    private static class CSVFormatProxy extends CSVFormat {
        private final CSVPrinter printer;

        CSVFormatProxy(CSVFormat base, CSVPrinter printer) {
            super(base.getDelimiter(),
                    base.getQuoteCharacter(),
                    base.getQuoteMode(),
                    base.getCommentMarker(),
                    base.getEscapeCharacter(),
                    base.getIgnoreSurroundingSpaces(),
                    base.getIgnoreEmptyLines(),
                    base.getRecordSeparator(),
                    base.getNullString(),
                    base.getHeaderComments(),
                    base.getHeader(),
                    base.getSkipHeaderRecord(),
                    base.getAllowMissingColumnNames(),
                    base.getIgnoreHeaderCase(),
                    base.getTrim(),
                    base.getTrailingDelimiter());
            this.printer = printer;
        }

        @Override
        public CSVPrinter print(final Appendable out) {
            return printer;
        }
    }
}
